<?php $page_title='Form sản phẩm';require __DIR__.'/_layout_start.php';require_once __DIR__.'/../models/AdminCatalog.php';$m=new AdminCatalog(db_connect());$id=(int)($_GET['id']??0);$p=$id?$m->findProduct($id):null;$cats=$m->categories();$brands=$m->brands();if(is_post()){if(!empty($_FILES['image']['name'])){$dir=__DIR__.'/../assets/uploads/products/';if(!is_dir($dir))mkdir($dir,0777,true);$name=time().'_'.preg_replace('/[^a-zA-Z0-9._-]/','_',$_FILES['image']['name']);move_uploaded_file($_FILES['image']['tmp_name'],$dir.$name);$_POST['hinh_anh_chinh']='assets/uploads/products/'.$name;}$m->saveProduct($_POST,$id);redirect('admin/products.php');}?><h1><?=$p?'Sửa':'Thêm'?> sản phẩm</h1><form method="post" enctype="multipart/form-data" class="bg-white p-4 rounded-4"><input name="ten_san_pham" class="form-control mb-2" placeholder="Tên" value="<?=h($p['ten_san_pham']??'')?>"><input name="ma_san_pham" class="form-control mb-2" placeholder="Mã" value="<?=h($p['ma_san_pham']??'')?>"><select name="id_danh_muc" class="form-select mb-2"><?php foreach($cats as $c):?><option value="<?=$c['id_danh_muc']?>" <?=($p['id_danh_muc']??'')==$c['id_danh_muc']?'selected':''?>><?=h($c['ten_danh_muc'])?></option><?php endforeach;?></select><select name="id_thuong_hieu" class="form-select mb-2"><?php foreach($brands as $b):?><option value="<?=$b['id_thuong_hieu']?>" <?=($p['id_thuong_hieu']??'')==$b['id_thuong_hieu']?'selected':''?>><?=h($b['ten_thuong_hieu'])?></option><?php endforeach;?></select><input name="gia" type="number" class="form-control mb-2" value="<?=h($p['gia']??0)?>"><input name="so_luong_ton" type="number" class="form-control mb-2" value="<?=h($p['so_luong_ton']??0)?>"><input name="hinh_anh_chinh" class="form-control mb-2" value="<?=h($p['hinh_anh_chinh']??'assets/images/no-image.jpg')?>"><input type="file" name="image" class="form-control mb-2"><textarea name="mo_ta_ngan" class="form-control mb-2"><?=h($p['mo_ta_ngan']??'')?></textarea><textarea name="mo_ta_chi_tiet" class="form-control mb-2"><?=h($p['mo_ta_chi_tiet']??'')?></textarea><select name="trang_thai" class="form-select mb-2"><option value="dang_ban">Đang bán</option><option value="het_hang">Hết hàng</option><option value="an">Ẩn</option></select><button class="btn btn-primary">Lưu</button></form><?php require __DIR__.'/_layout_end.php';?>
